+
+const HypothesisSchema = z.object({
+  hypothesis: z.string().min(1),
+  confidence: z.number().min(0).max(1),
+  evidence: z.array(z.string()),
+});
+
+const TodoItemSchema = z.object({
+  task: z.string().min(1),
