+/**
+ * Control plane event structure (from /collaboration/events)
+ */
+interface ControlPlaneEvent {
+  type:
+    | "node_added"
+    | "node_removed"
+    | "node_updated"
+    | "edge_added"
+    | "edge_removed"
+    | "edge_updated"
+    | "full_refresh";
