+/**
+ * Handoff Transfer Service - Resource transfer orchestration.
+ *
+ * Handles atomic transfer of:
+ * - File reservations
+ * - Checkpoint ownership
+ * - Pending Agent Mail messages
+ * - Active subscriptions
+ */
+
+import type {
+  HandoffRecord,
+  ResourceManifest,
+  TransferResult,
