+      projectId,
+      agentId: sourceAgentId,
+      patterns: reservation.patterns,
+      mode: reservation.mode,
+      ttl: reservation.ttl,
+      reason: "Restored after failed transfer",
+      taskId: reservation.metadata.taskId,
+    });
