+/** Index: source agent ID -> handoff IDs */
+const sourceAgentIndex: Map<string, Set<string>> = new Map();
+
+/** Index: target agent ID -> handoff IDs */
+const targetAgentIndex: Map<string, Set<string>> = new Map();
